        <button onClick={() => handleViewDocuments(row)} className="p-1.5 text-purple-600 hover:bg-purple-100 rounded-lg transition" title="View Documents"><FileText className="w-4 h-4" /></button>
        {/* ✅ Image button REMOVED (Fix 4) */}
